const inputData = $input.all();

const invoices = Array.isArray(inputData[0].json) ? inputData[0].json : (inputData[0].json.invoices || inputData[0].json.data || []);
const payments = Array.isArray(inputData[1].json) ? inputData[1].json : (inputData[1].json.payments || inputData[1].json.data || []);

const matched = [];
const unmatchedPayments = [];
const updatedInvoices = [];

// Try to match payments to invoices by reference or amount
payments.forEach(payment => {
  let found = false;

  // Match by invoice_reference if present
  if (payment.invoice_id) {
    const invoice = invoices.find(inv => inv.id === payment.invoice_id);
    if (invoice) {
      matched.push({
        invoiceId: invoice.id,
        paymentId: payment.id,
        amount: payment.amount,
        invoiceAmount: invoice.total_amount,
        matchType: 'direct_reference',
        clientId: invoice.client_id,
        clientName: invoice.client_name
      });
      updatedInvoices.push({
        id: invoice.id,
        status: Math.abs(payment.amount - invoice.total_amount) < 0.01 ? 'paid' : 'partial',
        paid_amount: payment.amount,
        payment_id: payment.id
      });
      found = true;
    }
  }

  // Try fuzzy match by client + amount
  if (!found) {
    const possibleInvoices = invoices.filter(inv => 
      inv.client_id === payment.client_id &&
      Math.abs(inv.total_amount - payment.amount) < 5
    );

    if (possibleInvoices.length === 1) {
      const invoice = possibleInvoices[0];
      matched.push({
        invoiceId: invoice.id,
        paymentId: payment.id,
        amount: payment.amount,
        invoiceAmount: invoice.total_amount,
        matchType: 'fuzzy_amount',
        clientId: invoice.client_id,
        clientName: invoice.client_name
      });
      updatedInvoices.push({
        id: invoice.id,
        status: 'paid',
        paid_amount: payment.amount,
        payment_id: payment.id
      });
      found = true;
    }
  }

  if (!found) {
    unmatchedPayments.push(payment);
  }
});

// Find overdue invoices (unpaid > 30 days)
const now = new Date();
const overdueInvoices = invoices.filter(inv => {
  if (inv.status === 'paid') return false;
  const dueDate = new Date(inv.due_date || inv.created_at);
  const daysDiff = (now - dueDate) / (1000 * 60 * 60 * 24);
  return daysDiff > 30;
});

return {
  matchedCount: matched.length,
  unmatchedCount: unmatchedPayments.length,
  overdueCount: overdueInvoices.length,
  matches: matched,
  unmatchedPayments: unmatchedPayments,
  overdueInvoices: overdueInvoices,
  invoicesToUpdate: updatedInvoices
};

